// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertArrayEquals;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.IOException;
import java.util.Arrays;

import org.eclipse.rdf4j.sail.lmdb.sketch.SketchFootprint;
import org.eclipse.rdf4j.sail.lmdb.sketch.SketchSnapshotIdentity;
import org.junit.jupiter.api.Test;

class ColdFilterSynopsisTest {

	private static final SketchSnapshotIdentity IDENTITY = new SketchSnapshotIdentity(11L, 29L, 7L);

	@Test
	void deterministicBottomKUsesFullTupleTieBreakAndIsOrderIndependent() throws IOException {
		ColdFilterSynopsis.Builder forward = ColdFilterSynopsis.builder(3);
		forward.offerHashed(1L, 1L, 9L, 2L, 3L, 4L);
		forward.offerHashed(1L, 1L, 3L, 2L, 3L, 4L);
		forward.offerHashed(1L, 1L, 5L, 2L, 3L, 4L);
		forward.offerHashed(1L, 1L, 1L, 2L, 3L, 4L);

		ColdFilterSynopsis.Builder reverse = ColdFilterSynopsis.builder(3);
		reverse.offerHashed(1L, 1L, 1L, 2L, 3L, 4L);
		reverse.offerHashed(1L, 1L, 5L, 2L, 3L, 4L);
		reverse.offerHashed(1L, 1L, 3L, 2L, 3L, 4L);
		reverse.offerHashed(1L, 1L, 9L, 2L, 3L, 4L);

		ColdFilterSynopsis first = forward.build();
		ColdFilterSynopsis second = reverse.build();
		assertEquals(3, first.retainedRows());
		assertEquals(4L, first.totalRows());
		assertFalse(first.complete());
		assertEquals(1L, first.subjectAt(0));
		assertEquals(3L, first.subjectAt(1));
		assertEquals(5L, first.subjectAt(2));
		assertArrayEquals(first.serialize(IDENTITY), second.serialize(IDENTITY));
	}

	@Test
	void unsignedRankOrderingRetainsTheLowestHashes() {
		ColdFilterSynopsis.Builder builder = ColdFilterSynopsis.builder(2);
		builder.offerHashed(-1L, 0L, 99L, 1L, 1L, 0L);
		builder.offerHashed(1L, 0L, 2L, 1L, 1L, 0L);
		builder.offerHashed(0L, 0L, 1L, 1L, 1L, 0L);

		ColdFilterSynopsis synopsis = builder.build();
		assertEquals(1L, synopsis.subjectAt(0));
		assertEquals(2L, synopsis.subjectAt(1));
	}

	@Test
	void footprintReportsExactPrimitiveAndSerializedBytes() throws IOException {
		ColdFilterSynopsis.Builder builder = ColdFilterSynopsis.builder(4);
		builder.offer(1L, 10L, 100L, 0L);
		builder.offer(2L, 10L, 101L, 0L);
		builder.offer(3L, 20L, 102L, 8L);

		ColdFilterSynopsis synopsis = builder.build();
		byte[] serialized = synopsis.serialize(IDENTITY);
		SketchFootprint footprint = synopsis.footprint();
		assertEquals(4, footprint.capacity());
		assertEquals(3, footprint.retainedRows());
		assertEquals(3L, footprint.totalRows());
		assertTrue(footprint.complete());
		assertEquals(3L * 6L * Long.BYTES, footprint.publishedPrimitiveBytes());
		assertEquals(4L * 6L * Long.BYTES, footprint.builderPrimitiveBytes());
		assertEquals(7L * 6L * Long.BYTES, footprint.builderPlusPublishedPeakPrimitiveBytes());
		assertEquals(serialized.length, footprint.serializedBytes());
		assertEquals(1L, footprint.predicateSupportMin());
		assertEquals(1L, footprint.predicateSupportP25());
		assertEquals(1L, footprint.predicateSupportP50());
		assertEquals(2L, footprint.predicateSupportP75());
		assertEquals(2L, footprint.predicateSupportP95());
		assertEquals(2L, footprint.predicateSupportMax());
	}

	@Test
	void persistenceRejectsWrongIdentityCorruptionTruncationAndCapacityMismatch() throws IOException {
		ColdFilterSynopsis.Builder builder = ColdFilterSynopsis.builder(2);
		builder.offer(Long.MAX_VALUE, 2L, 3L, 4L);
		builder.offer(5L, 6L, 7L, 8L);
		ColdFilterSynopsis expected = builder.build();
		byte[] serialized = expected.serialize(IDENTITY);

		ColdFilterSynopsis actual = ColdFilterSynopsis.deserialize(serialized, IDENTITY, 2);
		assertEquals(expected.retainedRows(), actual.retainedRows());
		assertTrue(actual.subjectAt(0) == Long.MAX_VALUE || actual.subjectAt(1) == Long.MAX_VALUE);
		assertArrayEquals(serialized, actual.serialize(IDENTITY));

		SketchSnapshotIdentity wrongIdentity = new SketchSnapshotIdentity(11L, 29L, 8L);
		assertThrows(IOException.class, () -> ColdFilterSynopsis.deserialize(serialized, wrongIdentity, 2));

		byte[] corrupt = serialized.clone();
		corrupt[corrupt.length / 2] ^= 0x01;
		assertThrows(IOException.class, () -> ColdFilterSynopsis.deserialize(corrupt, IDENTITY, 2));
		assertThrows(IOException.class,
				() -> ColdFilterSynopsis.deserialize(Arrays.copyOf(serialized, serialized.length - 1), IDENTITY, 2));
		assertThrows(IOException.class, () -> ColdFilterSynopsis.deserialize(serialized, IDENTITY, 1));
	}

	@Test
	void capacityIsStrictlyBounded() {
		assertThrows(IllegalArgumentException.class, () -> ColdFilterSynopsis.builder(-1));
		assertThrows(IllegalArgumentException.class, () -> ColdFilterSynopsis.builder(6_145));
	}

	@Test
	void zeroCapacityTracksTotalRowsWithoutRetainingStorage() throws IOException {
		ColdFilterSynopsis.Builder builder = ColdFilterSynopsis.builder(0);
		builder.offer(1L, 2L, 3L, 4L);
		builder.offer(5L, 6L, 7L, 8L);
		ColdFilterSynopsis synopsis = builder.build();

		assertEquals(0, synopsis.retainedRows());
		assertEquals(2L, synopsis.totalRows());
		assertFalse(synopsis.complete());
		assertEquals(0L, synopsis.footprint().publishedPrimitiveBytes());
		assertEquals(0L, synopsis.footprint().builderPrimitiveBytes());
		assertEquals(synopsis.serialize(IDENTITY).length, synopsis.footprint().serializedBytes());
	}
}
